class Solution:
    def merge_sort(self, nums: list[int]) -> bool:
        if len(nums) <= 1: return True
        mid = len(nums) // 2
        left = nums[:mid]
        right = nums[mid:]
        return self.merge_sorted(left) and self.merge_sorted(right) and self.merge(left, right)

    def merge_sorted(self, nums: list[int]) -> bool:
        if len(nums) <= 1: return True
        mid = len(nums) // 2
        left = nums[:mid]
        right = nums[mid:]
        return self.merge_sorted(left) and self.merge_sorted(right)

    def merge(self, left: list[int], right: list[int]) -> bool:
        result = []
        i = j = 0
        while i < len(left) and j < len(right):
            if left[i] <= right[j]:
                result.append(left[i])
                i += 1
            else:
                result.append(right[j])
                j += 1
        result.extend(left[i:])
        result.extend(right[j:])
        return result == sorted(nums)



