class Solution {
public:
    bool mergeSort(vector<int>& nums) {
        if (nums.size() <= 1) return true;
        merge_sorted(nums, 0, nums.size() - 1);
        return true;
    }

    bool merge_sorted(vector<int>& nums, int left, int right) {
        if (left >= right) return true;
        int mid = left + (right - left) / 2;
        merge_sorted(nums, left, mid);
        merge_sorted(nums, mid + 1, right);
        merge(nums, left, mid, right);
        return true;
    }

    void merge(vector<int>& nums, int left, int mid, int right) {
        int n1 = mid - left + 1;
        int n2 = right - mid;
        vector<int> left_arr(n1);
        vector<int> right_arr(n2);
        for (int i = 0; i < n1; ++i) left_arr[i] = nums[left + i];
        for (int i = 0; i < n2; ++i) right_arr[i] = nums[mid + 1 + i];
        int i = 0, j = 0, k = left;
        while (i < n1 && j < n2) {
            if (left_arr[i] <= right_arr[j]) {
                nums[k] = left_arr[i];
                i++;
            } else {
                nums[k] = right_arr[j];
                j++;
            }
            k++;
        }
        while (i < n1) {
            nums[k] = left_arr[i];
            i++;
            k++;
        }
        while (j < n2) {
            nums[k] = right_arr[j];
            j++;
            k++;
        }
    }
};
